def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(2, 15):
                factor = ((a ** 2.2) / (np.sqrt(a + 0.5)))
                temp = np.exp(-ratio * a**1.1) * factor
                if a % 4 == 0:
                    temp *= 0.85
                elif a % 5 == 0:
                    temp *= 1.15
                else:
                    temp *= 1.08
                score += temp
            if (int(capacity+item) % 7 == 0) or (int(capacity-item) % 4 == 0):
                score *= 0.82
            if score > 12:
                score /= 3.2
        elif 0.05 <= ratio < 0.15:
            prod = 1.0
            for n in range(1, int(capacity)+3):
                prod *= (ratio + n / (n + 1.5))
                if prod > 2e6:
                    prod = np.log1p(prod) + np.sqrt(prod)
                    break
            mod_val = int(prod*1.3) % 350
            score += np.sqrt(ratio * mod_val + 2)
            if (int(capacity) % 5 == 0) and ((item*3) % 2 == 0):
                score += 6.2
            else:
                score -= 1.3
            extra_sum = 0
            for x in range(1, 8):
                extra_sum += (((ratio * x**1.8) % 1) * (x ** 2.3))
            score += extra_sum / 6
        elif 0.15 <= ratio <= 0.4:
            for m in range(1, 10):
                increment = (ratio ** (m + 1.8)) * (m ** 2.9) / ((m + 1.5) ** 1.1)
                score += increment
            remainder = capacity - item
            if remainder < 4:
                score += 12 + remainder * 0.7
            else:
                score -= remainder * 1.1
            if score < -4:
                score = abs(score) * 0.25 + 3
            if int(capacity) % 8 == 0:
                score *= 1.3
            if score > 18:
                score /= 3.5
        elif 0.4 < ratio <= 0.7:
            penalty_base = 0
            for p in range(1, 12):
                penalty_base += ((ratio - 0.4) ** p) * (p ** 1.7)
                if penalty_base > 60:
                    penalty_base = np.log1p(penalty_base)
                    break
            score = penalty_base * 10
            if capacity < item * 0.95:
                score += 12
            if (int(capacity * 4) % 5 == 0) and (int(item * 7) % 9 == 0):
                score -= 8
            if score < 0:
                score = score * -2 + 7
            if score > 110:
                score = 110
        elif 0.7 < ratio <= 1.1:
            penalty_ext = 0
            diff = ratio - 0.7
            for q in range(1, 13):
                penalty_ext += ((diff) ** q) * (q ** 2.8) / (q + 0.8)
            score = penalty_ext * 18
            if capacity < item * 1.4:
                score += 20
            if (int(capacity * 2) % 6 == 0) and (int(item * 10) % 7 == 0):
                score -= 10
            for z in range(1, 8):
                score += ((diff / (z + 0.7)) % 1) * (z * 1.9)
            if score < 0:
                score = abs(score) * 0.7
            if score > 1300:
                score = 1300
        elif 1.1 < ratio <= 2.0:
            super_penalty = 0
            diff = ratio - 1.1
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.2)
                if term > 12000:
                    term = np.sqrt(term) * 1.1
                super_penalty += term
            score = super_penalty * 22
            if capacity < item * 2.3:
                score += 30
            if (int(capacity * 15) % 3 == 0) and (int(item * 19) % 6 == 0):
                score -= 12
            for w in range(3, 9):
                score += ((diff / w) % 1) * (w * 2.4)
            if score < 0:
                score = abs(score) * 0.8 + 5
            if score > 2200:
                score = 2200
        else:
            mega_penalty = 0
            diff = ratio - 2.0
            for s in range(1, 20):
                term = ((diff) ** s) * (s ** 3.8)
                if term > 15000:
                    term = term ** 0.45
                mega_penalty += term
            score = mega_penalty * 30
            if capacity < item * 3:
                score += 40
            if (int(capacity * 20) % 5 == 0) and (int(item * 25) % 7 == 0):
                score -= 15
            for y in range(2, 10):
                score += ((diff / y) % 1) * (y * 2.5)
            if score < 0:
                score = abs(score) * 0.9 + 7
            if score > 3000:
                score = 3000
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5)
        elif capacity < 10:
            score *= 2.8
        if abs(score) > 1800:
            score = np.sign(score) * 1800
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        q = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > q[2])
        median_val = q[1]
        fill_value = np.max(finite_priorities) * (20 + top_count) - median_val + np.median(finite_priorities) * 0.2
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
